                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          {activeAction === 'started' ? "We'll send your access link to" :"We'll reach out with demo details to"}
